// src/components/CategoryCard/index.jsx
import React from 'react';
import { Link } from 'react-router-dom';
// Предполагаемый utils для получения полного URL
// import { getImageUrl } from '../../utils/fixUrl'; 
import s from './CategoryCard.module.css';

// Заглушка для функции, если не определена
const getImageUrl = (image) => image ? `http://localhost:3333${image}` : '/placeholder.jpg';

const CategoryCard = ({ id, title, image }) => {
  const imageUrl = getImageUrl(image);

  return (
    <Link to={`/categories/${id}`} className={s.cardLink}>
        <div className={s.categoryCard}>

            {/* Квадратная обертка для изображения */}
            <div className={s.imageWrapper}>
                <img src={imageUrl} alt={title} className={s.image} />
            </div>

            {/* Название под изображением */}
            <p className={s.title}>{title}</p>

        </div>
    </Link>
  );
};

export default CategoryCard;
